+import type { AnyColumn } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+/** A boundary for a window frame. */
+export type WindowFrameBoundary =
+	| typeof unboundedPreceding
+	| typeof currentRow
+	| typeof unboundedFollowing
+	| WindowFrameOffset;
+
+interface WindowFrameOffset {
+	kind: 'preceding' | 'following';
+	value: number;
+}
+
+export const unboundedPreceding = { kind: 'unbounded preceding' } as const;
+export const currentRow = { kind: 'current row' } as const;
+export const unboundedFollowing = { kind: 'unbounded following' } as const;
+
+function frameOffset(kind: 'preceding' | 'following', value: number): WindowFrameOffset {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${kind}() requires a non-negative integer; received ${value}`);
+	}
+	return { kind, value };
+}
+
+/** Creates an N PRECEDING frame boundary. */
+export function preceding(value: number): WindowFrameBoundary {
+	return frameOffset('preceding', value);
+}
+
+/** Creates an N FOLLOWING frame boundary. */
+export function following(value: number): WindowFrameBoundary {
+	return frameOffset('following', value);
+}
+
+export interface WindowFrame {
+	kind: 'rows' | 'range';
+	from: WindowFrameBoundary;
+	to?: WindowFrameBoundary;
+}
+
+function boundaryOrder(boundary: WindowFrameBoundary): number {
+	if (boundary === unboundedPreceding) return -Infinity;
+	if (boundary === currentRow) return 0;
+	if (boundary === unboundedFollowing) return Infinity;
+	return boundary.kind === 'preceding' ? -boundary.value : boundary.value;
+}
+
+function createFrame(kind: WindowFrame['kind'], spec: { from: WindowFrameBoundary; to?: WindowFrameBoundary }): WindowFrame {
+	if (spec.to !== undefined && boundaryOrder(spec.from) > boundaryOrder(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be after the "to" boundary');
+	}
+	return { kind, ...spec };
+}
+
+/** Creates a ROWS window frame. */
+export function rows(spec: { from: WindowFrameBoundary; to?: WindowFrameBoundary }): WindowFrame {
+	return createFrame('rows', spec);
+}
+
+/** Creates a RANGE window frame. */
+export function range(spec: { from: WindowFrameBoundary; to?: WindowFrameBoundary }): WindowFrame {
+	return createFrame('range', spec);
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+function boundarySql(boundary: WindowFrameBoundary): SQL {
+	if (boundary === unboundedPreceding) return sql.raw('unbounded preceding');
+	if (boundary === currentRow) return sql.raw('current row');
+	if (boundary === unboundedFollowing) return sql.raw('unbounded following');
+	return sql.raw(`${boundary.value} ${boundary.kind}`);
+}
+
+/** @internal */
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const parts: SQL[] = [];
+	if (spec.partitionBy) {
+		const values = Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
+		parts.push(sql`partition by ${sql.join(values, sql`, `)}`);
+	}
+	if (spec.orderBy) {
+		const values = Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
+		parts.push(sql`order by ${sql.join(values, sql`, `)}`);
+	}
+	if (spec.frame) {
+		const frame = spec.frame;
+		parts.push(frame.to === undefined
+			? sql`${sql.raw(frame.kind)} ${boundarySql(frame.from)}`
+			: sql`${sql.raw(frame.kind)} between ${boundarySql(frame.from)} and ${boundarySql(frame.to)}`);
+	}
+	return sql.join(parts, sql` `);
+}
+
+type ExpressionData<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer U> ? U : unknown;
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec?: WindowSpec | string): SQL<T> {
+		if (typeof spec === 'string') return sql`${this.expression} over ${sql.identifier(spec)}`;
+		return sql`${this.expression} over (${spec ? buildWindowSpec(spec) : sql.empty()})`;
+	}
+
+	getSQL(): SQL<T> {
+		return this.expression;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positiveInteger(functionName: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${functionName}() requires a positive integer; received ${value}`);
+	}
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+export function ntile(buckets: number): WindowFunction<number> {
+	positiveInteger('ntile', buckets);
+	return windowFunction('ntile', [sql.raw(String(buckets))]);
+}
+
+export function lag<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<
+	undefined extends typeof defaultValue ? ExpressionData<T> | null : Exclude<ExpressionData<T>, null>
+> {
+	const args: SQLWrapper[] = [expression];
+	if (offset !== undefined) args.push(sql.raw(String(offset)));
+	if (defaultValue !== undefined) args.push(defaultValue);
+	return windowFunction('lag', args) as any;
+}
+export function lead<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<
+	undefined extends typeof defaultValue ? ExpressionData<T> | null : Exclude<ExpressionData<T>, null>
+> {
+	const args: SQLWrapper[] = [expression];
+	if (offset !== undefined) args.push(sql.raw(String(offset)));
+	if (defaultValue !== undefined) args.push(defaultValue);
+	return windowFunction('lead', args) as any;
+}
+export function firstValue<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('first_value', [expression]); }
+export function lastValue<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('last_value', [expression]); }
+export function nthValue<T extends SQLWrapper>(expression: T, n: number): WindowFunction<ExpressionData<T> | null> {
+	positiveInteger('nthValue', n);
+	return windowFunction('nth_value', [expression, sql.raw(String(n))]);
+}
+
+export function windowSum(expression: SQLWrapper): WindowFunction<string | null> { return windowFunction('sum', [expression]); }
+export function windowAvg(expression: SQLWrapper): WindowFunction<string | null> { return windowFunction('avg', [expression]); }
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('min', [expression]); }
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('max', [expression]); }
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> { return windowFunction('count', expression ? [expression] : [sql.raw('*')]); }
